import axios from "axios"
import { useContext, useState } from "react"
import { UserContext } from "../context/UserContext"
import {useNavigate} from 'react-router-dom'

const LoginPage =()=>{

  const [logData,setLogData] = useState({
    email:'',
    password:''
  })
 const {setUser} = useContext(UserContext)

  const navigate = useNavigate()
  const handleChange =(e)=>{
    setLogData({...logData,[e.target.name]:e.target.value})
   }


   async function handleSubmit(e){
    e.preventDefault()
    try {
      axios.defaults.headers.common.Authorization = `Bearer ${data.token}`
      const {data}= await axios.post('/auth/login',logData)
      console.log(data)
      setUser(data)
      navigate('/')
    } catch (error) {
     
      // console.log(error.response.data.msg)

      if (error.response) {
        console.log('Server responded with status:', error.response.status);
        console.log('Error data:', error.response.data);
      } else if (error.request) {
        console.log('No response received from the server:', error.request);
      } else {
        console.log('Error during request setup:', error.message);
      }


    }
   }
   

    return <div>
      <div>
      <h1 className="mx-auto m-4 w-28">Login PAGE</h1>
      <div>
        <form action="" className="flex justify-center"  onSubmit={handleSubmit}>
          <div className="flex flex-col w-96 ">
            <input type="text" placeholder="EMAIL" name="email" value={logData.email} onChange={handleChange}/>
            <input type="text" placeholder="PASSWORD" name="password" value={logData.password} onChange={handleChange}/>
            <button className="">LOG IN</button>
          </div>
        </form>
      </div>
    </div>
    </div>
}

export default LoginPage;
